-- Reversión: reinsertar la cita del cronograma de Apelación (BIA)
-- ---------------------------------------------------------------------------
-- Contexto: 2026-07-21 se eliminó la única cita del cronograma
-- (`service_appointment_schedule`) de la fase única de Apelación
-- (service_phase_id f62fafe4-f5ef-49ac-9565-919d8c2a3ce1) para que la cita
-- DEJE DE SER REQUISITO del traspaso sales→legal (Vanessa→Diana). El gate del
-- traspaso es data-driven: el ítem `citas` solo aplica cuando el cronograma de
-- la fase tiene ≥1 cita (citasTotal>0). Con 0 filas → citasTotal=0 → no bloquea.
--
-- Para DESHACER (volver a exigir/mostrar la cita de bienvenida de Apelación),
-- ejecutar este INSERT (restaura id, objetivos y timestamps originales):

insert into public.service_appointment_schedule (id, service_phase_id, sequence_number, duration_minutes, kind, week_offset, label_i18n, position, objectives_i18n, created_at, updated_at) values ('59e6750e-0831-481a-8af2-bb2429d2202c','f62fafe4-f5ef-49ac-9565-919d8c2a3ce1',1,30,'video',1,NULL,0,'[{"id": "c92d440c-d94f-407c-afb1-f1661f439130", "text": {"en": "Review the 3 documents, confirm the 30-day deadline, and validate the EOIR-26 data.", "es": "Dar la bienvenida y explicar el proceso de Apelación (BIA)"}}, {"id": "094efe1c-3417-4345-af16-7d979fff913f", "text": {"en": "Clarification: Usa Latino Prime is a document preparation platform; we are NOT legal advice.", "es": "Aclarar: Usa Latino Prime es una plataforma de preperación de documentos, NO somos asesoría legal"}}, {"id": "8318bef2-ec89-4061-8520-057cd5779207", "text": {"en": "Confirm the exact date of the judge''s decision (oral or written)", "es": "Confirmar la fecha exacta de la decisión del juez (oral o escrita)"}}, {"id": "98e4028b-07bc-44d6-95fe-8a69dccda561", "text": {"en": "Calculate and schedule Day 30 (deadline for receipt at the BIA)", "es": "Calcular y calendarizar el DÍA 30 (fecha límite de recepción en la BIA)"}}, {"id": "29093e41-aba9-4c77-abb5-ef76fcb235b7", "text": {"en": "Explain the 30-day period and that the date of receipt counts, not the date of sending.", "es": "Explicar el plazo de 30 días y que cuenta la fecha de recepción, no de envío"}}, {"id": "ddc7ee0f-73fa-44b8-939f-334231869fd7", "text": {"en": "Explain the fee: $1,030 (2026), or request a waiver with EOIR-26A (filed with EOIR-26)", "es": "Explicar la tarifa: $1,030 (2026), o solicitar exención con EOIR-26A (se presenta junto al EOIR-26)"}}, {"id": "fd7b71fe-0fdd-4a9a-bbda-bc878afdc541", "text": {"en": "Payment only through the EOIR Payment Portal — starting Feb 2026, checks and money orders will no longer be accepted.", "es": "Pago solo por el EOIR Payment Portal — desde feb 2026 ya no se aceptan cheques ni money orders"}}, {"id": "b5f1f742-76c9-4f14-9f3c-205a6bec771b", "text": {"en": "Review the list of documents and hide the documents that do not apply.", "es": "Revisar las lista de documentos y ocultar los documentos que no corresponde"}}, {"id": "3dfdddd2-724f-4551-b17c-2c58a62b6482", "text": {"en": "Teach how your platform works and how to access your case", "es": "Enseñar como funciona su plataforma y como entrar a su caso"}}, {"id": "833d82b2-0944-4d6c-9154-3fabf23b6c34", "text": {"en": "Teach him/her how to schedule an appointment", "es": "Enseñarle como agendar cita"}}, {"id": "4b556bce-465d-439a-be9e-a7cd1299d345", "text": {"en": "Teach him/her how to upload documents", "es": "Enseñarle como subir documentos"}}, {"id": "38e49084-3e9d-451a-ad01-c516fa98977a", "text": {"en": "File standard: always scanned; clear, complete, and only what is requested (do not mix with other documents)", "es": "Estándar de archivos: siempre escaneados; nítido, completo y unicamente lo que le solicita (no mezclar con otros documentos)"}}, {"id": "e9d85c49-a2ef-4bd7-8b3f-adb4128e8c9e", "text": {"en": "To teach him/her how to answer the questionnaires on the forms", "es": "Enseñarle a como responder los cuestionarios de los formularios"}}, {"id": "7c62f0aa-e6c4-4a18-9d9a-e8d9d4c1497b", "text": {"en": "Fill out the questionnaires honestly, clearly, in detail, and coherently.", "es": "Llenar los cuestionarios de manera honesta, clara, detallada y coherente."}}, {"id": "da8769c3-b466-487a-b06c-b7b79d2b9b57", "text": {"en": "All the required documents are uploaded", "es": "Todos los documentos requeridos están cargados"}}, {"id": "ef7b81ee-da49-48a8-b4ef-c7098e681411", "text": {"en": "Correct quality: legible, complete, scanned (no photos)", "es": "Calidad correcta: legible, completo, escaneado (no fotos)"}}, {"id": "2befd579-edc2-44e5-8fd6-f543a8bfad60", "text": {"en": "If the documents are correct, they are approved.", "es": "Si estan correcto los documentos, se aprueban"}}, {"id": "e9d5cc4e-247f-4ede-9f1b-bb1ab7be98cf", "text": {"en": "Review the EOIR-26 and EOIR-26A questionnaires (if applicable)", "es": "Revisar el custionario EOIR-26 y EOIR-26A (si aplica)"}}, {"id": "cbc4eef3-d200-4ae8-82a9-166b91c8351d", "text": {"en": "Please note that your file will be ready within 4 days.", "es": "Mencionar que en un plazo de 4 días estará listo su expediente"}}]','2026-07-17 14:42:38.705064+00',now());
